class TeeLogger:
    """Дублирует stdout/stderr в консоль и в файл (файл перезаписывается)"""
    def __init__(self, filename):
        self.terminal_stdout = sys.__stdout__   # оригинальный stdout
        self.terminal_stderr = sys.__stderr__   # оригинальный stderr
        self.log_file = open(filename, 'w', encoding='utf-8')

    def write(self, message):
        self.terminal_stdout.write(message)
        self.log_file.write(message)
        self.log_file.flush()

    def flush(self):
        self.terminal_stdout.flush()
        self.log_file.flush()

    def close(self):
        self.log_file.close()

def setup_session_logging(log_filename="session.log"):
    tee = TeeLogger(log_filename)
    sys.stdout = tee
    sys.stderr = tee
    # Печатаем тестовое сообщение, чтобы убедиться, что файл пишется
    print(f"[LOG] Логирование включено. Файл: {log_filename}")
    return tee

def compute_dcm_from_seconds(idx1, idx2, tf_minutes):
    """
    idx1, idx2: start_time и end_time в секундах (timestamp)
    15 и 30 это поправка на лунные циклы (маятник фуко) для фильтра шума.
    Возвращает (dog_ts, cat_ts, manul_ts) в секундах.
    """
    tf_15 = 15 * tf_minutes * 60
    tf_30 = 30 * tf_minutes * 60
    tf_1 = -1 * tf_minutes * 60
    
    FirstTimeGAS3 = idx2 + (idx2 - idx1)
    
    FirstGasCorrect15 = idx1 + tf_15
    FirstFakeGAS15diff = abs(FirstTimeGAS3 - FirstGasCorrect15) / 2
    FirstFakeGAS15 = FirstTimeGAS3 + tf_1 + FirstFakeGAS15diff
    
    FirstGasCorrect30 = idx1 + tf_30
    FirstGas30diff = abs(FirstTimeGAS3 - FirstGasCorrect30) / 2
    FirstGas30 = FirstTimeGAS3 + tf_1 + FirstGas30diff
    
    FirstGas23diff = (FirstGas30 - FirstFakeGAS15) / 2
    FirstGas23 = round(FirstFakeGAS15 + FirstGas23diff)
    
    FirstTimeGAS4 = FirstTimeGAS3 + (FirstTimeGAS3 - idx1)
    FirstMiddleGAS = FirstTimeGAS3 + (FirstTimeGAS3 - idx2)
    
    FirstEchoGASdiff15 = abs(FirstMiddleGAS - FirstGasCorrect15) / 2
    FirstEchoGAS15 = FirstTimeGAS4 + FirstEchoGASdiff15
    
    FirstEchoGASdiff30 = abs(FirstMiddleGAS - FirstGasCorrect30) / 2
    FirstEchoGAS30 = FirstTimeGAS4 + FirstEchoGASdiff30
    
    FirstEchoGASdiff23 = (FirstEchoGAS30 - FirstEchoGAS15) / 2
    FirstEchoGAS23 = round(FirstEchoGAS15 + FirstEchoGASdiff23)
    
    FirstFinalGASdiff23 = (FirstEchoGAS23 - FirstGas23) / 2
    FirstFinalGAS23 = round(FirstGas23 + FirstFinalGASdiff23)
    
    FirstEndGASdiff = abs(FirstEchoGAS23 - FirstFinalGAS23) / 2
    FirstEndGAS = round(FirstFinalGAS23 + FirstEndGASdiff)
    
    FirstEndGASdiff19 = abs(FirstFinalGAS23 - FirstGas23) / 2
    FirstEndGAS19 = round(FirstGas23 + FirstEndGASdiff19)
    
    return FirstGas23, FirstEndGAS, FirstEndGAS19   # dog, cat, manul
