def fix_qt_plugin():
    """Исправляет ошибку с Qt плагинами"""
    try:
        import PyQt5
        
        # Получаем путь к PyQt5
        pyqt_path = os.path.dirname(PyQt5.__file__)
        print(f"[QT] PyQt5 установлен в: {pyqt_path}")
        
        # Ищем папку с плагинами
        possible_plugin_paths = [
            os.path.join(pyqt_path, 'Qt', 'plugins'),
            os.path.join(pyqt_path, 'plugins'),
            os.path.join(pyqt_path, 'Qt5', 'plugins'),
            os.path.join(sys.prefix, 'Library', 'plugins'),
            os.path.join(sys.prefix, 'lib', 'site-packages', 'PyQt5', 'Qt', 'plugins'),
        ]
        
        found_path = None
        for path in possible_plugin_paths:
            platforms_path = os.path.join(path, 'platforms')
            if os.path.exists(platforms_path) and os.path.exists(os.path.join(platforms_path, 'qwindows.dll')):
                found_path = path
                print(f"[QT] Найден путь к плагинам: {found_path}")
                break
        
        if found_path:
            os.environ['QT_QPA_PLATFORM_PLUGIN_PATH'] = found_path
            print(f"[QT] Установлен QT_QPA_PLATFORM_PLUGIN_PATH = {found_path}")
            return True
        
        # Если не нашли, пробуем рекурсивный поиск
        import glob
        search_pattern = os.path.join(pyqt_path, '**', 'qwindows.dll')
        found = glob.glob(search_pattern, recursive=True)
        if found:
            plugin_dir = os.path.dirname(found[0])
            os.environ['QT_QPA_PLATFORM_PLUGIN_PATH'] = plugin_dir
            print(f"[QT] Найден qwindows.dll в: {plugin_dir}")
            return True
            
    except Exception as e:
        print(f"[QT] Ошибка: {e}")
    
    return False

# Вызываем функцию
fix_qt_plugin()

# Также добавляем путь к переменной окружения для Windows
