class SkynetSplashScreen(QtWidgets.QDialog):
    """Анимированная заставка (без фона)"""
    def __init__(self, parent=None, duration_ms=5000):
        super().__init__(parent)
        
        self.setWindowFlags(
            QtCore.Qt.WindowType.FramelessWindowHint | 
            QtCore.Qt.WindowType.WindowStaysOnTopHint
        )
        self.setAttribute(QtCore.Qt.WidgetAttribute.WA_TranslucentBackground)
        
        layout = QtWidgets.QVBoxLayout(self)
        layout.setContentsMargins(0, 0, 0, 0)
        
        self.label = QtWidgets.QLabel()
        self.label.setScaledContents(True)
        layout.addWidget(self.label)
        
        # Загружаем GIF
        current_dir = os.path.dirname(os.path.abspath(__file__))
        gif_path = os.path.join(current_dir, "giflogoskynet.gif")
        
        self.frames = []
        self.current_frame = 0
        
        if os.path.exists(gif_path):
            try:
                from PIL import Image
                gif = Image.open(gif_path)
                
                for frame_num in range(gif.n_frames):
                    try:
                        gif.seek(frame_num)
                        # Сохраняем прозрачность
                        if gif.mode == 'P':
                            frame = gif.convert('RGBA')
                        else:
                            frame = gif.convert('RGBA')
                        
                        data = frame.tobytes("raw", "RGBA")
                        qimage = QtGui.QImage(data, frame.width, frame.height, QtGui.QImage.Format_RGBA8888)
                        pixmap = QtGui.QPixmap.fromImage(qimage)
                        
                        if not pixmap.isNull():
                            scaled = pixmap.scaled(960, 960,
                                QtCore.Qt.AspectRatioMode.KeepAspectRatio,
                                QtCore.Qt.TransformationMode.SmoothTransformation)
                            self.frames.append(scaled)
                    except:
                        continue
                
                if self.frames:
                    self.label.setPixmap(self.frames[0])
                    self.animation_timer_id = self.startTimer(40)
            except Exception as e:
                print(f"[ЗАСТАВКА] Ошибка: {e}")
        else:
            print(f"[ЗАСТАВКА] Файл не найден")
        
        self.resize(1000, 1000)
        screen = QtWidgets.QApplication.primaryScreen().geometry()
        self.move(screen.center() - self.rect().center())
        
        self.close_timer = QtCore.QTimer()
        self.close_timer.setSingleShot(True)
        self.close_timer.timeout.connect(self.close)
        self.close_timer.start(duration_ms)
    
    def timerEvent(self, event):
        if self.frames:
            self.current_frame = (self.current_frame + 1) % len(self.frames)
            self.label.setPixmap(self.frames[self.current_frame])
    
    def closeEvent(self, event):
        if hasattr(self, 'animation_timer_id'):
            self.killTimer(self.animation_timer_id)
        if hasattr(self, 'close_timer'):
            self.close_timer.stop()
        event.accept()

