class AutoLimbDebugger(QtCore.QThread):
    finished_signal = QtCore.pyqtSignal(dict)
    error_signal = QtCore.pyqtSignal(str)
    log_signal = QtCore.pyqtSignal(str)
    progress_signal = QtCore.pyqtSignal(int)

    def __init__(self, ch_config, timeframe, target_id):
        """
        ch_config: dict с ключами host, port, user, password
        """
        super().__init__()
        self.ch_config = ch_config
        self.timeframe = timeframe
        self.target_id = target_id
        self._is_running = True
        self._client = None   # будет создан в run()

    def _get_impulse_type_and_subtype(self, id_val, timeframe):
        """
        Возвращает (impulse_type, subtype) для указанного ID и таймфрейма.
        Если данных нет, возвращает (None, None).
        Логирует результат.
        """
        try:
            query = f"""
                SELECT impulse_type, subtype
                FROM crypto_data.impulse_ids
                WHERE id = {id_val} AND timeframe = '{timeframe}'
                LIMIT 1
            """
            rows = self._client.execute(query)
            if rows:
                impulse_type, subtype = rows[0]
                self.log_signal.emit(
                    f"[ИМПУЛЬС-ТИП] ID {id_val} (ТФ {timeframe}): тип={impulse_type}, подтип={subtype}"
                )
                return impulse_type, subtype
            else:
                self.log_signal.emit(
                    f"[ИМПУЛЬС-ТИП] ID {id_val} (ТФ {timeframe}) не найден в impulse_ids"
                )
                return None, None
        except Exception as e:
            self.log_signal.emit(f"[ИМПУЛЬС-ТИП] Ошибка для ID {id_val}: {str(e)}")
            return None, None

    def _find_organ_right_point_non_inverted_max(self, start_dt, end_dt):
        """
        Ищет long_end с максимальным close (без ограничений).
        Используется как fallback.
        """
        query = f"""
            SELECT sp.timestamp, c.close
            FROM crypto_data.shifted_points sp
            JOIN crypto_data.btc_usdt_{self.timeframe} c ON sp.timestamp = c.timestamp
            WHERE sp.timeframe = '{self.timeframe}'
              AND sp.shift_type = 'long_end'
              AND sp.timestamp > '{start_dt.strftime('%Y-%m-%d %H:%M:%S')}'
              AND sp.timestamp <= '{end_dt.strftime('%Y-%m-%d %H:%M:%S')}'
            ORDER BY c.close DESC
            LIMIT 1
        """
        rows = self._client.execute(query)
        if not rows:
            return None, None
        best_ts, best_close = rows[0]
        prev_open = self._get_prev_open_at_time(best_ts)
        if prev_open is None:
            prev_open = best_close
        return best_ts, prev_open

