class LimbDSMAnalyzer:
    """Анализатор конечностей (ХВОСТ/УСЫ/ОРГАН) по методу DCM"""
    
    def __init__(self, results_table, timeframe_manager):
        self.results_table = results_table
        self.timeframe_manager = timeframe_manager
        self.limb_analysis_file = "LIMB_ANALYSIS_DATA.json"
        self.limb_data = self.load_limb_data()
        
        # Загружаем GROUP_TIMES_DATA.json для доступа к реальным датам групп
        self.group_times_data = self.load_group_times_data()
        
        # Константы DCM (как в оригинале, всё в секундах)
        self.TF_15 = 15 * 60   # 900 секунд
        self.TF_30 = 30 * 60   # 1800 секунд
        self.TF_1 = -60        # -60 секунд
        
        # Таймфреймы для усреднения
        self.avg_timeframes = ['30m', '1h', '4h']
    
    def load_group_times_data(self):
        """Загружает GROUP_TIMES_DATA.json для доступа к датам групп"""
        if os.path.exists("GROUP_TIMES_DATA.json"):
            try:
                with open("GROUP_TIMES_DATA.json", 'r', encoding='utf-8') as f:
                    return json.load(f)
            except:
                return {}
        return {}
    
    def load_limb_data(self):
        """Загружает сохранённые анализы конечностей"""
        if os.path.exists(self.limb_analysis_file):
            try:
                with open(self.limb_analysis_file, 'r', encoding='utf-8') as f:
                    return json.load(f)
            except:
                return {"last_update": "", "limb_analysis": {}}
        return {"last_update": "", "limb_analysis": {}}
    
    def save_limb_data(self):
        """Сохраняет анализы конечностей"""
        try:
            self.limb_data["last_update"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
            with open(self.limb_analysis_file, 'w', encoding='utf-8') as f:
                json.dump(self.limb_data, f, indent=2, ensure_ascii=False)
            return True
        except Exception as e:
            print(f"[LIMB_DCM] Ошибка сохранения: {e}")
            return False
    
    def get_averaged_time_for_group(self, position_id, group_key):
        """
        Получает усреднённое время для группы по всем таймфреймам.
        group_key: 'group5_times', 'group6_times' и т.д.
        Возвращает timestamp в секундах или None.
        """
        times = []
        group_data = self.group_times_data.get(group_key, {})
        
        for tf in self.avg_timeframes:
            tf_data = group_data.get(tf, {})
            time_str = tf_data.get(str(position_id))
            if time_str:
                try:
                    dt = datetime.strptime(time_str, '%Y-%m-%d %H:%M:%S')
                    times.append(dt.timestamp())
                except:
                    pass
        
        if not times:
            return None
        
        return sum(times) / len(times)
    
    def get_limb_times(self, position_id, limb_type):
        """
        Возвращает (start_sec, end_sec) для указанной конечности.
        limb_type: 'hvost', 'usy', 'organ'
        """
        if limb_type == 'hvost':
            group1_key = 'group1_times'
            group2_key = 'group2_times'
        elif limb_type == 'usy':
            group1_key = 'group3_times'
            group2_key = 'group4_times'
        elif limb_type == 'organ':
            group1_key = 'group5_times'
            group2_key = 'group6_times'
        else:
            return None, None
        
        start_sec = self.get_averaged_time_for_group(position_id, group1_key)
        end_sec = self.get_averaged_time_for_group(position_id, group2_key)
        
        return start_sec, end_sec
    
    def calculate_dcm_from_seconds(self, start_sec, end_sec):
        """
        Оригинальная формула DCM, работающая с секундами.
        Возвращает (dog_sec, cat_sec, manul_sec).
        """
        if start_sec is None or end_sec is None:
            return None, None, None
        
        idx1 = start_sec
        idx2 = end_sec
        
        # ========== ОРИГИНАЛЬНЫЙ DCM (калька с DCMResultsManager) ==========
        FirstTimeGAS3 = idx2 + (idx2 - idx1)
        
        FirstGasCorrect15 = idx1 + self.TF_15
        FirstFakeGAS15diff = abs(FirstTimeGAS3 - FirstGasCorrect15) / 2
        FirstFakeGAS15 = FirstTimeGAS3 + self.TF_1 + FirstFakeGAS15diff
        
        FirstGasCorrect30 = idx1 + self.TF_30
        FirstGas30diff = abs(FirstTimeGAS3 - FirstGasCorrect30) / 2
        FirstGas30 = FirstTimeGAS3 + self.TF_1 + FirstGas30diff
        
        FirstGas23diff = (FirstGas30 - FirstFakeGAS15) / 2
        FirstGas23 = round(FirstFakeGAS15 + FirstGas23diff)
        
        # Эхо-расчёт
        FirstTimeGAS4 = FirstTimeGAS3 + (FirstTimeGAS3 - idx1)
        FirstMiddleGAS = FirstTimeGAS3 + (FirstTimeGAS3 - idx2)
        
        FirstEchoGASdiff15 = abs(FirstMiddleGAS - FirstGasCorrect15) / 2
        FirstEchoGAS15 = FirstTimeGAS4 + FirstEchoGASdiff15
        
        FirstEchoGASdiff30 = abs(FirstMiddleGAS - FirstGasCorrect30) / 2
        FirstEchoGAS30 = FirstTimeGAS4 + FirstEchoGASdiff30
        
        FirstEchoGASdiff23 = (FirstEchoGAS30 - FirstEchoGAS15) / 2
        FirstEchoGAS23 = round(FirstEchoGAS15 + FirstEchoGASdiff23)
        
        FirstFinalGASdiff23 = (FirstEchoGAS23 - FirstGas23) / 2
        FirstFinalGAS23 = round(FirstGas23 + FirstFinalGASdiff23)
        
        FirstEndGASdiff = abs(FirstEchoGAS23 - FirstFinalGAS23) / 2
        FirstEndGAS = round(FirstFinalGAS23 + FirstEndGASdiff)
        
        FirstEndGASdiff19 = abs(FirstFinalGAS23 - FirstGas23) / 2
        FirstEndGAS19 = round(FirstGas23 + FirstEndGASdiff19)
        
        # ========== РЕЗУЛЬТАТЫ ==========
        dog_sec = FirstEndGAS19
        cat_sec = FirstEndGAS
        manul_sec = FirstFinalGAS23
        
        return dog_sec, cat_sec, manul_sec
    
    def analyze_id_limb(self, position_id, limb_type, force_recalc=False):
        """
        Анализирует одну конечность одного ID.
        Использует реальные даты из GROUP_TIMES_DATA.json и оригинальный DCM.
        """
        # Проверяем кэш
        id_str = str(position_id)
        if not force_recalc and id_str in self.limb_data.get("limb_analysis", {}):
            if limb_type in self.limb_data["limb_analysis"][id_str]:
                cached = self.limb_data["limb_analysis"][id_str][limb_type]
                if cached.get("status") == "calculated":
                    return cached
        
        # Получаем реальные времена для конечности
        start_sec, end_sec = self.get_limb_times(position_id, limb_type)
        
        if start_sec is None or end_sec is None:
            print(f"[LIMB_DCM] ID {position_id}, {limb_type}: нет данных в GROUP_TIMES_DATA.json")
            return None
        
        # Оригинальный DCM
        dog_sec, cat_sec, manul_sec = self.calculate_dcm_from_seconds(start_sec, end_sec)
        
        if dog_sec is None:
            return None
        
        # Конвертируем секунды в минуты для хранения (как в твоём файле)
        start_min = start_sec / 60.0
        end_min = end_sec / 60.0
        original_dog_min = (end_sec - start_sec) / 60.0
        
        # Определяем знак для ОРГАНА (если start > end, то отрицательный)
        limb_sign = '+'
        if limb_type == 'organ' and start_sec > end_sec:
            limb_sign = '-'
            # Для отрицательного сигнала меняем знак у прогнозов
            # (в DCM они всегда положительные, но если конечность перевёрнута, то и прогноз переворачиваем)
            dog_sec = -dog_sec
            cat_sec = -cat_sec
            manul_sec = -manul_sec
        
        # Сохраняем результат
        analysis_data = {
            "start_sec": start_sec,
            "end_sec": end_sec,
            "start_min": start_min,
            "end_min": end_min,
            "sign": limb_sign,
            "dcm_prediction": {
                "dog": dog_sec / 60.0,      # минуты (как в твоём файле)
                "cat": cat_sec / 60.0,
                "manul": manul_sec / 60.0
            },
            "original_dog": original_dog_min,
            "status": "calculated",
            "last_calculation": datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        }
        
        # Обновляем кэш
        if id_str not in self.limb_data["limb_analysis"]:
            self.limb_data["limb_analysis"][id_str] = {}
        self.limb_data["limb_analysis"][id_str][limb_type] = analysis_data
        self.save_limb_data()
        
        return analysis_data
    
    def analyze_all_limbs_for_id(self, position_id, force_recalc=False):
        """Анализирует все три конечности для одного ID"""
        result = {}
        for limb_type in ['hvost', 'usy', 'organ']:
            result[limb_type] = self.analyze_id_limb(position_id, limb_type, force_recalc)
        return result
    
    def analyze_all_ids(self, progress_callback=None):
        """Анализирует все конечности всех ID"""
        row_count = self.results_table.rowCount()
        analyzed = 0
        
        for row in range(row_count):
            id_item = self.results_table.item(row, 0)
            if not id_item or not id_item.text().strip():
                continue
            
            try:
                position_id = int(id_item.text())
                self.analyze_all_limbs_for_id(position_id, force_recalc=True)
                analyzed += 1
                
                if progress_callback:
                    progress_callback(row + 1, row_count)
                    
            except Exception as e:
                print(f"[LIMB_DCM] Ошибка для ID {id_item.text()}: {e}")
                continue
        
        return analyzed
    
    def get_row_by_id(self, position_id):
        """Возвращает индекс строки по ID"""
        for row in range(self.results_table.rowCount()):
            item = self.results_table.item(row, 0)
            if item and item.text() == str(position_id):
                return row
        return None

class ImpulseStatisticsWorker(QtCore.QThread):
    progress_signal = QtCore.pyqtSignal(int, int)
    finished_signal = QtCore.pyqtSignal(dict)
    error_signal = QtCore.pyqtSignal(str)
    log_signal = QtCore.pyqtSignal(str)

    def __init__(self, ch_manager, timeframe, start_dt, end_dt, limit, timestamps, highs, lows, closes):
        super().__init__()
        self.ch_manager = ch_manager
        self.timeframe = timeframe
        self.start_dt = start_dt
        self.end_dt = end_dt
        self.limit = limit
        self.timestamps = timestamps
        self.highs = highs
        self.lows = lows
        self.closes = closes
        self._is_running = True
        self._logged_ids = set()
        # Параметры для параллельной обработки
        self.batch_size = 10000   # кол-во ID в одном чанке
        self.workers = 8          # число потоков

    def stop(self):
        self._is_running = False

    def run(self):
        try:
            if len(self.timestamps) == 0:
                self.error_signal.emit("Нет данных графика для указанного таймфрейма")
                return

            min_ts = self.timestamps[0]
            max_ts = self.timestamps[-1]
            min_dt = datetime.fromtimestamp(min_ts / 1000.0)
            max_dt = datetime.fromtimestamp(max_ts / 1000.0)
            self.log_signal.emit(f"Доступный диапазон данных: {min_dt} – {max_dt}")

            # Загружаем ID
            query = f"""
                SELECT id, start_time, end_time, direction
                FROM crypto_data.auto_ids
                WHERE timeframe = '{self.timeframe}'
                  AND start_time >= '{min_dt.strftime('%Y-%m-%d %H:%M:%S')}'
                  AND end_time <= '{max_dt.strftime('%Y-%m-%d %H:%M:%S')}'
                  AND start_time >= '{self.start_dt.strftime('%Y-%m-%d %H:%M:%S')}'
                  AND end_time <= '{self.end_dt.strftime('%Y-%m-%d %H:%M:%S')}'
                LIMIT {self.limit}
            """
            rows = self.ch_manager.client.execute(query)
            total = len(rows)
            self.log_signal.emit(f"Загружено {total} ID для обработки (в диапазоне данных)")

            if total == 0:
                self.finished_signal.emit({'total': 0})
                return

            # Подготовка данных для быстрого поиска
            ts_list = self.timestamps / 1000.0   # numpy массив
            ts_to_idx = {ts: i for i, ts in enumerate(ts_list.tolist())}

            # Разбиваем на чанки
            id_chunks = [rows[i:i+self.batch_size] for i in range(0, total, self.batch_size)]
            self.log_signal.emit(f"Разбито на {len(id_chunks)} чанков, потоков: {self.workers}")

            # Общая статистика (с блокировкой)
            from threading import Lock
            stats_lock = Lock()
            stats = {'total': total, 'type0': 0, 'type1': 0, 'type2': 0, 'type3': 0,
                     'type4': 0, 'type5': 0, 'type6': 0, 'type7': 0, 'type8': 0,
                     'subtypes': {'normal': 0, 'short-anomaly': 0, 'long-anomaly': 0},
                     'directions': {'long': 0, 'short': 0},
                     'skipped_empty': 0,
                     'sample_ids': {'type': {}, 'subtype': {}, 'direction': {}}}
            processed = 0

            from concurrent.futures import ThreadPoolExecutor, as_completed
            import time
            start_time = time.time()

            with ThreadPoolExecutor(max_workers=self.workers) as executor:
                futures = []
                for chunk in id_chunks:
                    if not self._is_running:
                        break
                    futures.append(executor.submit(
                        self._process_chunk,
                        chunk, ts_list, ts_to_idx, stats, stats_lock
                    ))

                for future in as_completed(futures):
                    if not self._is_running:
                        break
                    try:
                        chunk_stats = future.result(timeout=300)
                        # Обновляем общую статистику (уже сделано внутри с блокировкой)
                        processed += len(chunk_stats.get('ids_processed', 0))
                        self.progress_signal.emit(processed, total)
                        self.log_signal.emit(f"Обработано {processed}/{total} ID")
                    except Exception as e:
                        self.log_signal.emit(f"Ошибка в потоке: {str(e)}")

            elapsed = time.time() - start_time
            self.log_signal.emit(f"Обработка завершена за {elapsed:.2f} сек. Всего: {total}, пропущено из-за пустых списков: {stats['skipped_empty']}")
            self.finished_signal.emit(stats)

        except Exception as e:
            self.error_signal.emit(str(e))
            import traceback
            self.log_signal.emit(traceback.format_exc())

    def _process_chunk(self, chunk, ts_list, ts_to_idx, stats, stats_lock):
        """
        Обрабатывает один чанк ID, обновляет общую статистику.
        Возвращает словарь с числом обработанных ID (для прогресса).
        """
        import numpy as np
        import bisect
        from datetime import datetime

        processed_ids = []
        chunk_stats = {'ids_processed': []}

        # Локальные ссылки для ускорения
        highs = self.highs
        lows = self.lows
        closes = self.closes

        for row in chunk:
            if not self._is_running:
                break
            id_val, start_dt, end_dt, direction = row
            try:
                start_ts = start_dt.timestamp()
                end_ts = end_dt.timestamp()

                # ---- БЫСТРЫЙ ПОИСК ИНДЕКСОВ С NUMPY ----
                left = ts_to_idx.get(start_ts)
                if left is None:
                    left = np.searchsorted(ts_list, start_ts, side='left')
                    if left >= len(ts_list):
                        left = len(ts_list) - 1
                    elif abs(ts_list[left] - start_ts) > 1:
                        left = np.searchsorted(ts_list, start_ts, side='right') - 1

                right = ts_to_idx.get(end_ts)
                if right is None:
                    right = np.searchsorted(ts_list, end_ts, side='right') - 1
                    if right < 0:
                        right = 0
                    elif abs(ts_list[right] - end_ts) > 1:
                        right = np.searchsorted(ts_list, end_ts, side='left')

                if left < 0:
                    left = 0
                if right >= len(ts_list):
                    right = len(ts_list) - 1

                if right - left < 4:
                    with stats_lock:
                        stats['type0'] += 1
                        if 0 not in stats['sample_ids']['type']:
                            stats['sample_ids']['type'][0] = id_val
                    processed_ids.append(id_val)
                    continue

                # ---- ФОРМИРУЕМ ИНДЕКСЫ (как в оригинале) ----
                if direction == 'long':
                    first3_indices = list(range(left+1, min(left+4, len(ts_list))))
                    rest_after_first = list(range(left+4, right+1))
                    last3_indices = list(range(max(left+1, right-2), right+1))
                    rest_before_last = list(range(left+1, max(left+1, right-2)))
                else:
                    last3_indices = list(range(max(left+1, right-3), right))
                    rest_before_last = list(range(left+1, right-3))
                    first3_indices = list(range(left+1, min(left+4, len(ts_list))))
                    rest_after_first = list(range(left+4, right+1))

                if (len(first3_indices) == 0 or len(rest_after_first) == 0 or
                    len(last3_indices) == 0 or len(rest_before_last) == 0):
                    with stats_lock:
                        stats['type0'] += 1
                        stats['skipped_empty'] += 1
                        if 0 not in stats['sample_ids']['type']:
                            stats['sample_ids']['type'][0] = id_val
                    processed_ids.append(id_val)
                    continue

                # ---- ВЫЧИСЛЕНИЕ ЭКСТРЕМУМОВ (векторизовано) ----
                max_high_first3 = np.max(highs[first3_indices])
                max_close_first3 = np.max(closes[first3_indices])
                min_low_first3 = np.min(lows[first3_indices])
                min_close_first3 = np.min(closes[first3_indices])

                max_high_rest_after = np.max(highs[rest_after_first])
                max_close_rest_after = np.max(closes[rest_after_first])
                min_low_rest_after = np.min(lows[rest_after_first])
                min_close_rest_after = np.min(closes[rest_after_first])

                max_high_last3 = np.max(highs[last3_indices])
                max_close_last3 = np.max(closes[last3_indices])
                min_low_last3 = np.min(lows[last3_indices])
                min_close_last3 = np.min(closes[last3_indices])

                max_high_rest_before = np.max(highs[rest_before_last])
                max_close_rest_before = np.max(closes[rest_before_last])
                min_low_rest_before = np.min(lows[rest_before_last])
                min_close_rest_before = np.min(closes[rest_before_last])

                # ---- КОРРЕКТИРОВКА ДЛЯ LONG И SHORT (как в оригинале) ----
                if direction == 'long':
                    min_low_first3 = min_low_rest_before
                    min_close_first3 = min_close_rest_before
                    min_low_rest_after = min_low_last3
                    min_close_rest_after = min_close_last3
                    start_idx = np.searchsorted(ts_list, start_ts, side='left')
                    if start_idx < len(ts_list) and abs(ts_list[start_idx] - start_ts) > 1:
                        start_idx = left
                    first_close_indices = [start_idx + i for i in range(3) if start_idx + i < len(closes)]
                    if first_close_indices:
                        max_close_first3 = np.max(closes[first_close_indices])
                    first_high_indices = [start_idx + i for i in range(3) if start_idx + i < len(highs)]
                    if first_high_indices:
                        max_high_first3 = np.max(highs[first_high_indices])
                else:  # short
                    max_high_first3 = max_high_rest_before
                    max_close_first3 = max_close_rest_before
                    max_high_rest_after = max_high_last3
                    max_close_rest_after = max_close_last3
                    start_idx = np.searchsorted(ts_list, start_ts, side='left')
                    if start_idx < len(ts_list) and abs(ts_list[start_idx] - start_ts) > 1:
                        start_idx = left
                    first_low_indices = [start_idx + i for i in range(3) if start_idx + i < len(lows)]
                    if first_low_indices:
                        min_low_first3 = np.min(lows[first_low_indices])
                    first_close_indices_short = [start_idx + i for i in range(3) if start_idx + i < len(closes)]
                    if first_close_indices_short:
                        min_close_first3 = np.min(closes[first_close_indices_short])

                # ---- КЛАССИФИКАЦИЯ ТИПА ----
                impulse_type = 0
                if direction == 'long':
                    if (min_close_rest_after < min_close_first3) and (max_close_rest_after > max_close_first3):
                        impulse_type = 1
                    elif (min_close_first3 < min_close_rest_after) and (max_close_first3 > max_close_rest_after):
                        impulse_type = 2
                    elif (min_close_first3 < min_close_rest_after) and (max_close_rest_after > max_close_first3):
                        impulse_type = 3
                    elif (min_close_rest_after < min_close_first3) and (max_close_first3 > max_close_rest_after):
                        impulse_type = 7
                    else:
                        impulse_type = 0
                else:
                    if (min_close_first3 < min_close_rest_after) and (max_close_first3 > max_close_rest_after):
                        impulse_type = 4
                    elif (min_close_rest_after < min_close_first3) and (max_close_rest_after > max_close_first3):
                        impulse_type = 5
                    elif (min_close_rest_after < min_close_first3) and (max_close_first3 > max_close_rest_after):
                        impulse_type = 6
                    elif (min_close_first3 < min_close_rest_after) and (max_close_rest_after > max_close_first3):
                        impulse_type = 8
                    else:
                        impulse_type = 0

                # ---- ПОДТИП ----
                start_price = closes[left] if left < len(closes) else 0
                end_price = closes[right] if right < len(closes) else 0
                subtype = 'normal'
                if direction == 'short' and end_price > start_price:
                    subtype = 'short-anomaly'
                elif direction == 'long' and end_price < start_price:
                    subtype = 'long-anomaly'

                # ---- ОБНОВЛЕНИЕ СТАТИСТИКИ (с блокировкой) ----
                with stats_lock:
                    stats[f'type{impulse_type}'] = stats.get(f'type{impulse_type}', 0) + 1
                    stats['subtypes'][subtype] = stats['subtypes'].get(subtype, 0) + 1
                    stats['directions'][direction] = stats['directions'].get(direction, 0) + 1
                    if impulse_type not in stats['sample_ids']['type']:
                        stats['sample_ids']['type'][impulse_type] = id_val
                    if subtype not in stats['sample_ids']['subtype']:
                        stats['sample_ids']['subtype'][subtype] = id_val
                    if direction not in stats['sample_ids']['direction']:
                        stats['sample_ids']['direction'][direction] = id_val

                processed_ids.append(id_val)

            except Exception as e:
                with stats_lock:
                    stats['errors'] = stats.get('errors', 0) + 1
                self.log_signal.emit(f"Ошибка ID {id_val}: {str(e)}")
                processed_ids.append(id_val)

        # Возвращаем количество обработанных ID (для прогресса)
        return {'ids_processed': processed_ids}
    

