    def add_event_for_id(self, position_id, parent_dialog):
        """Открывает диалог добавления события для указанного ID"""
        dialog = QtWidgets.QDialog(parent_dialog)
        dialog.setWindowTitle(f"➕ Добавить событие для ID {position_id}")
        dialog.setMinimumSize(550, 450)
        
        layout = QtWidgets.QVBoxLayout(dialog)
        
        # Информация о текущем ID
        info_label = QtWidgets.QLabel(f"📌 Создание события для ID {position_id}")
        info_label.setStyleSheet("color: #FFD700; font-weight: bold;")
        layout.addWidget(info_label)
        
        # Поле заголовка
        title_label = QtWidgets.QLabel("Заголовок:")
        title_edit = QtWidgets.QLineEdit()
        title_edit.setPlaceholderText("Краткое описание события (например: 'Удар по Ирану', 'Паника на рынке AI')")
        layout.addWidget(title_label)
        layout.addWidget(title_edit)
        
        # Поле текста
        content_label = QtWidgets.QLabel("Содержание:")
        content_edit = QtWidgets.QTextEdit()
        content_edit.setPlaceholderText("Подробное описание новости или события...\n\nПример:\n- Что произошло\n- Когда\n- Какое влияние на рынок\n- Связь с другими ID")
        content_edit.setMinimumHeight(200)
        layout.addWidget(content_label)
        layout.addWidget(content_edit)
        
        # Поле тегов
        tags_label = QtWidgets.QLabel("Теги (через запятую):")
        tags_edit = QtWidgets.QLineEdit()
        tags_edit.setPlaceholderText("Например: SELL, Геополитика, Иран, AI, Паника")
        layout.addWidget(tags_label)
        layout.addWidget(tags_edit)
        
        # Кнопки
        buttons = QtWidgets.QHBoxLayout()
        btn_save = QtWidgets.QPushButton("💾 Сохранить")
        btn_save.setStyleSheet("background-color: #2E7D32; color: white; font-weight: bold;")
        btn_cancel = QtWidgets.QPushButton("❌ Отмена")
        
        def on_save():
            title = title_edit.text().strip()
            content = content_edit.toPlainText().strip()
            tags = [t.strip() for t in tags_edit.text().split(',') if t.strip()]
            
            if not title:
                QtWidgets.QMessageBox.warning(dialog, "Ошибка", "Введите заголовок")
