    def show_correction_dialog(self):
        """Показывает диалог корректировки как независимое окно"""
        try:
            # Создаем диалог и передаем auto_lines_manager и chain_manager
            dialog = CorrectionDialog(
                self.timeframe_manager, 
                self.main_win,
                self.auto_lines_manager,
                self.chain_manager
            )
            
            # ⭐ СОХРАНЯЕМ ССЫЛКУ НА ДИАЛОГ ⭐
            self.correction_dialog = dialog
            
            # ⭐ ПЕРЕДАЕМ ССЫЛКУ В AVERAGE_MANAGER ⭐
            if hasattr(self, 'average_manager'):
                self.average_manager.set_correction_dialog(dialog)
                print("[ГРАФИК] Ссылка на CorrectionDialog передана в AverageResultsManager")
            else:
                print("[ГРАФИК] ОШИБКА: average_manager не найден")
            
            # ⭐ ПЕРЕДАЕМ ДАННЫЕ ГРАФИКА ⭐
            if hasattr(self, 'timestamps') and self.timestamps is not None:
                dialog.set_chart_data(self.timestamps, self.highs, self.lows)
                print(f"[ГРАФИК] Передано {len(self.timestamps)} точек в диалог")
            
            # Настраиваем как независимое окно
            dialog.setWindowFlags(
                QtCore.Qt.WindowType.Window |
                QtCore.Qt.WindowType.WindowCloseButtonHint |
                QtCore.Qt.WindowType.WindowMinimizeButtonHint |
                QtCore.Qt.WindowType.WindowMaximizeButtonHint
            )
            
            # Убираем модальность
            dialog.setModal(False)
            dialog.setWindowModality(QtCore.Qt.WindowModality.NonModal)
            
            # Показываем окно
            dialog.show()
            
            # Сохраняем ссылку для предотвращения сборки мусора
            if not hasattr(self, 'correction_dialogs'):
                self.correction_dialogs = []
            self.correction_dialogs.append(dialog)
            
            # Удаляем из списка при закрытии
            dialog.destroyed.connect(lambda: self.correction_dialogs.remove(dialog))
            
        except Exception as e:
            QtWidgets.QMessageBox.critical(
                self.main_win,
                "Ошибка",
                f"Не удалось открыть окно корректировки:\n{str(e)}"
            )
            import traceback
            traceback.print_exc()
    
    def setup_plot(self):
        """Настройка графика с защитой от переполнения"""
        pg.setConfigOptions(useOpenGL=True)
        fmt = QtGui.QSurfaceFormat()
        fmt.setSamples(0)  
        fmt.setSwapInterval(0)  
        QtGui.QSurfaceFormat.setDefaultFormat(fmt)
        self.plot = self.graphics_view.addPlot(axisItems={'bottom': SafeTimeAxisItem(orientation='bottom')})
        self.plot.getViewBox().setLimits(
            xMin=-1e18, xMax=1e18,
            yMin=-1e18, yMax=1e18
        )
        self.plot.showGrid(x=True, y=True, alpha=0.2)
        self.plot.setLabel('bottom', "Time")
        self.plot.setLabel('left', "Price")
        self.vb = self.plot.getViewBox()
        self.vb.setMouseMode(pg.ViewBox.PanMode)
        self.vb.setMenuEnabled(False)
        self.vb.setMouseEnabled(x=True, y=True)
        self.plot.ctrlMenu = None  
        self.plot.setDownsampling(auto=True, mode='peak')
        self.plot.setClipToView(True)
