    def check_data_visibility(self):
        """Проверка видимости данных на графике"""
        try:
            view_range = self.plot.vb.viewRange()
            x_min, x_max = view_range[0]
            y_min, y_max = view_range[1]
            if hasattr(self, 'timestamps') and len(self.timestamps) > 0:
                data_x_min = np.min(self.timestamps)
                data_x_max = np.max(self.timestamps)
                if data_x_max < x_min or data_x_min > x_max:
                    self.set_initial_scale()
        except Exception as e:
            print(f"Ошибка проверки видимости: {str(e)}")            
